fun solve(s: String): Long {
    val n = s.length
    val count = arrayOf<Int>(0, 0, 0) // count of 'L', 'C', 'T'

    // Count occurrences of 'L', 'C', 'T' in the string
    for (c in s) {
        when (c) {
            'L' -> count[0]++
            'C' -> count[1]++
            'T' -> count[2]++
        }
    }

    // Precompute prefix and suffix counts
    val prefix = arrayOf<Int>(0, 0, 0)
    val suffix = arrayOf<Int>(0, 0, 0)

    var l = 0
    var c = 0
    var t = 0

    // Compute prefix counts
    for (i in 0 until n) {
        when (s[i]) {
            'L' -> l++
            'C' -> c++
            'T' -> t++
        }
        prefix[i] = intArrayOf(l, c, t)
    }

    // Compute suffix counts
    var l2 = 0
    var c2 = 0
    var t2 = 0

    for (i in n - 1 downTo 0) {
        when (s[i]) {
            'L' -> l2++
            'C' -> c2++
            'T' -> t2++
        }
        suffix[i] = intArrayOf(l2, c2, t2)
    }

    var max = 0L

    // Try inserting 'L' at every possible position
    for (i in 0..n) {
        val lCount = if (i == 0) 1 else prefix[i - 1][0]
        val cCount = prefix[i][1]
        val tCount = suffix[i][2]
        max = max.let { maxOf(it, (lCount.toLong() * cCount.toLong() * tCount.toLong())) }
    }

    // Try inserting 'C' at every possible position
    for (i in 0..n) {
        val lCount = prefix[i][0]
        val cCount = if (i == 0) 1 else prefix[i - 1][1]
        val tCount = suffix[i][2]
        max = max.let { maxOf(it, (lCount.toLong() * cCount.toLong() * tCount.toLong())) }
    }

    // Try inserting 'T' at every possible position
    for (i in 0..n) {
        val lCount = prefix[i][0]
        val cCount = prefix[i][1]
        val tCount = if (i == 0) 1 else suffix[i - 1][2]
        max = max.let { maxOf(it, (lCount.toLong() * cCount.toLong() * tCount.toLong())) }
    }

    return max
}
